Here's a Python script that checks for updates on installed packages using pip:

```python
import pip
import subprocess

def check_packages():
    packages = [package.project_name for package in pip.get_installed_distributions()]
    updated_packages = []

    for package in packages:
        try:
            subprocess.check_output(['pip', 'install', '--upgrade', package])
        except subprocess.CalledProcessError:
            updated_packages.append(package)

    if updated_packages:
        print(f"The following packages need to be updated: {', '.join(updated_packages)}")
    else:
        print("All packages are up-to-date.")

check_packages()
